CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_process_steps (id SERIAL PRIMARY KEY, process_id INTEGER NOT NULL, step_order INTEGER NOT NULL DEFAULT 0, title TEXT NOT NULL, role_name TEXT, description TEXT, input_desc TEXT, output_desc TEXT, system_name TEXT, document_name TEXT, duration_minutes INTEGER, is_manual BOOLEAN NOT NULL DEFAULT TRUE, pain_point TEXT, control_point TEXT, automation_potential TEXT NOT NULL DEFAULT 'none', ai_potential TEXT NOT NULL DEFAULT 'none', is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_psteps ON t_p61016064_digital_innovation_i.wb_process_steps(process_id, step_order);